where slug = 'travel';

do $$
declare
  v_uid uuid; v_bp_id uuid; v_bp_app text; v_bp_vertical text; v_bp_preset jsonb; v_org uuid;
begin
  select id into v_uid from auth.users
    order by (email = 'femi@phoxta.com') desc, created_at asc limit 1;
  if v_uid is null then raise notice '[travel seed] no auth user yet — skipping'; return; end if;

  select id, app_path, vertical, coalesce(preset, '{}'::jsonb)
    into v_bp_id, v_bp_app, v_bp_vertical, v_bp_preset
    from blueprints where slug = 'travel';

  select id into v_org from organizations where slug = 'travel-demo';
  if v_org is null then
    insert into organizations (owner_user_id, name, slug, vertical, blueprint_id, stage,
                               lifecycle_stage, app_path, modules, provisioned_at)
    values (v_uid, 'Travel', 'travel-demo', coalesce(v_bp_vertical, 'travel'), v_bp_id, 'trial',
            'operating', coalesce(v_bp_app, 'businesses/travel'), v_bp_preset, now())
    returning id into v_org;
  end if;
  raise notice '[travel seed] org id = %', v_org;
end $$;
